parameters:
{
  "sources": {
    "breweries": {
      "db": "stg",
      "table": "OpenBreweryDB_Breweries",
      "business_keys": [
        "brewery_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND brewery_id IS NOT NULL"
      }
    }
  },
  "target": {
    "db": "int",
    "table": "Brewery_Master",
    "business_keys": [
      "Brewery_ID"
    ],
    "write_mode": "truncate_insert"
  },
  "transformation": {
    "steps": [
      {
        "step_id": 10,
        "name": "read_breweries",
        "type": "read_source",
        "config": {
          "source_name": "breweries",
          "alias": "df_breweries"
        }
      },
      {
        "step_id": 20,
        "name": "dedup_breweries",
        "type": "deduplicate",
        "config": {
          "input_df": "df_breweries",
          "alias": "df_dedup",
          "use_source_business_keys": true,
          "source_name": "breweries",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 30,
        "name": "select_brewery_master",
        "type": "select",
        "config": {
          "input_df": "df_dedup",
          "alias": "df_selected",
          "columns": [
            {
              "expr": "brewery_id",
              "alias": "Brewery_ID"
            },
            {
              "expr": "brewery_name",
              "alias": "Brewery_Name"
            },
            {
              "expr": "brewery_type",
              "alias": "Brewery_Type"
            },
            {
              "expr": "city",
              "alias": "City"
            },
            {
              "expr": "state_province",
              "alias": "State_Province"
            },
            {
              "expr": "country",
              "alias": "Country"
            },
            {
              "expr": "longitude",
              "alias": "Longitude"
            },
            {
              "expr": "latitude",
              "alias": "Latitude"
            },
            {
              "expr": "website_url",
              "alias": "Website_URL"
            },
            {
              "expr": "stg_load_date",
              "alias": "stg_load_date"
            },
            {
              "expr": "batch_id",
              "alias": "batch_id"
            }
          ]
        }
      },
      {
        "step_id": 40,
        "name": "add_system_fields",
        "type": "add_system_fields",
        "config": {
          "input_df": "df_selected",
          "alias": "df_with_sys"
        }
      },
      {
        "step_id": 50,
        "name": "compute_hash",
        "type": "compute_hash",
        "config": {
          "input_df": "df_with_sys",
          "alias": "df_hashed"
        }
      },
      {
        "step_id": 60,
        "name": "write_target",
        "type": "write_target",
        "config": {
          "input_df": "df_hashed"
        }
      }
    ]
  }
}
